import logo from './logo.svg';
import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css'
import { BrowserRouter,Routes,Route,Link } from 'react-router-dom';
import Getproducts from './components/Getproducts';
import Signin from './components/Signin';
import Signup from './components/Signup';
import Addproduct from './components/Addproduct';
import Mpesapayment from './components/Mpesapayment';
import Navbar from './components/Navbar';






function App() {
  return (
    <BrowserRouter>
    <div className="App">
      {/* navbar goes here  */}
      <Navbar/>

      <header className="bg-warning">
        <h1 className='text-info text-center'> Welcome to sokogarden</h1>


      </header>
      {/* navigations  */}
      <nav>
        <Link to = "/Signin" className='btn btn-info me-2'> Signin</Link>
        <Link to = "/Signup" className='btn btn-info me-2'> Signup</Link>
        <Link to = "/Addproduct" className='btn btn-info me-2'>Addproduct</Link>
        <Link to = "/" className='btn btn-info me-2'> Getproducts</Link>



      </nav>
      {/* Routes goes here  */}
      <Routes>
        <Route path='/signin' element = {<Signin/>}/>
        <Route path='/signup' element = {<Signup/>}/>
        <Route path='/Addproduct' element = {<Addproduct/>}/>
        <Route path='/' element = {<Getproducts/>}/>
        <Route path='/mpesa' element = {<Mpesapayment/>}/>

      </Routes>

      foo
    </div>
      </BrowserRouter>
  );
}

export default App;
